import{_ as a,o as r,c as d,a2 as e}from"./chunks/framework.ZhLefgN8.js";const p=JSON.parse('{"title":"ETF 行情与全景","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/etf-overview.md","filePath":"zh-CN/market-data/etf-overview.md"}'),l={name:"market-data/etf-overview.md"};function o(i,t,n,h,s,u){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="etf-行情与全景" tabindex="-1">ETF 行情与全景 <a class="header-anchor" href="#etf-行情与全景" aria-label="Permalink to &quot;ETF 行情与全景&quot;">​</a></h1><p>ETF（交易所交易基金）详情页分为多个标签，其中<strong>行情</strong>和<strong>全景</strong>是最常用的两个核心标签，分别提供实时报价数据和基金基本面信息。</p><p>入口：长桥 App - 市场/自选 - 点击 ETF 标的进入详情页</p><h2 id="行情-tab" tabindex="-1">行情 Tab <a class="header-anchor" href="#行情-tab" aria-label="Permalink to &quot;行情 Tab&quot;">​</a></h2><h3 id="基本行情数据" tabindex="-1">基本行情数据 <a class="header-anchor" href="#基本行情数据" aria-label="Permalink to &quot;基本行情数据&quot;">​</a></h3><p>页面顶部展示 ETF 的核心报价信息：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>最新价 / 涨跌幅</td><td>当前成交价及较昨收的涨跌幅</td></tr><tr><td>昨收</td><td>上一交易日收盘价</td></tr><tr><td>今开</td><td>当日开盘价</td></tr><tr><td>最高 / 最低</td><td>当日最高价和最低价</td></tr><tr><td>成交量</td><td>当日累计成交股数</td></tr><tr><td>成交额</td><td>当日累计成交金额</td></tr><tr><td>振幅</td><td>（最高价 - 最低价）/ 昨收价</td></tr><tr><td>换手率</td><td>成交量 / 流通股本</td></tr><tr><td>量比</td><td>当日成交量与近期均量的比值</td></tr><tr><td>委比</td><td>（买盘委托量 - 卖盘委托量）/ 总委托量，反映买卖力度对比</td></tr><tr><td>均价</td><td>当日成交均价（成交额 / 成交量）</td></tr><tr><td>总市值 / 流通市值</td><td>总股本 / 流通股本对应市值</td></tr><tr><td>总股本 / 流通股本</td><td>ETF 总份额和可流通份额</td></tr><tr><td>每手</td><td>最小交易单位</td></tr><tr><td>货币</td><td>计价货币（如 USD、HKD）</td></tr><tr><td>52 周高 / 52 周低</td><td>近 52 周最高价和最低价</td></tr><tr><td>每股净资产</td><td>基金单位净值</td></tr><tr><td>每股收益</td><td>EPS（适用于有分红的 ETF）</td></tr><tr><td>市盈率</td><td>PE（TTM / 动态 / 静态可切换）</td></tr><tr><td>市净率</td><td>PB</td></tr><tr><td>股息 / 股息率</td><td>近期每股分红金额及对应股息率</td></tr></tbody></table><h3 id="盘前-盘后交易" tabindex="-1">盘前 / 盘后交易 <a class="header-anchor" href="#盘前-盘后交易" aria-label="Permalink to &quot;盘前 / 盘后交易&quot;">​</a></h3><p>支持美股盘前和盘后延长时段行情，顶部显示当前交易时段状态（如「盘前交易中 美东时间」），盘前价格和涨跌幅单独展示。</p><h3 id="bbo-最优买卖报价" tabindex="-1">BBO（最优买卖报价） <a class="header-anchor" href="#bbo-最优买卖报价" aria-label="Permalink to &quot;BBO（最优买卖报价）&quot;">​</a></h3><p>显示当前买一价和卖一价（Best Bid &amp; Offer），以及对应的委托量，帮助判断即时买卖报价水平。</p><h3 id="深度摆盘" tabindex="-1">深度摆盘 <a class="header-anchor" href="#深度摆盘" aria-label="Permalink to &quot;深度摆盘&quot;">​</a></h3><ul><li>默认显示买卖双方各 5 档报价和委托量</li><li>订阅 <strong>Nasdaq TotalView</strong> 后可查看 60 档深度摆盘，获取更完整的市场深度数据</li><li>买盘（绿色）/ 卖盘（红色）分列展示，直观显示多空力量分布</li></ul><h3 id="k-线图表" tabindex="-1">K 线图表 <a class="header-anchor" href="#k-线图表" aria-label="Permalink to &quot;K 线图表&quot;">​</a></h3><p>支持多周期切换：</p><ul><li><strong>分时图</strong>：1 分钟实时走势，含成交量</li><li><strong>日 K / 周 K / 月 K / 年 K</strong>：不同周期蜡烛图</li><li><strong>5 日分时</strong>：近 5 个交易日连续分时走势</li></ul><p>内置常用技术指标：</p><ul><li><strong>MACD</strong>：趋势与动量指标</li><li><strong>KDJ</strong>：超买超卖判断</li><li><strong>RSI</strong>：相对强弱指数</li><li><strong>VOL</strong>：成交量柱状图</li></ul><h3 id="资金流向" tabindex="-1">资金流向 <a class="header-anchor" href="#资金流向" aria-label="Permalink to &quot;资金流向&quot;">​</a></h3><p>展示 ETF 的资金流入流出情况：</p><ul><li><strong>实时资金流向</strong>：当日按大单 / 中单 / 小单分类的资金流入和流出金额（单位：万元）</li><li><strong>历史资金流向</strong>：近期多日资金流向趋势，判断主力资金动向</li></ul><h3 id="做空数据" tabindex="-1">做空数据 <a class="header-anchor" href="#做空数据" aria-label="Permalink to &quot;做空数据&quot;">​</a></h3><p>展示 ETF 的做空相关统计数据，帮助了解市场空头仓位情况。</p><h3 id="成交统计" tabindex="-1">成交统计 <a class="header-anchor" href="#成交统计" aria-label="Permalink to &quot;成交统计&quot;">​</a></h3><p>按买卖方向和单笔成交规模统计当日成交分布情况。</p><h3 id="大家也在关注" tabindex="-1">大家也在关注 <a class="header-anchor" href="#大家也在关注" aria-label="Permalink to &quot;大家也在关注&quot;">​</a></h3><p>与当前 ETF 相关的其他标的（同行业或关联板块），显示各标的当日涨跌幅，便于横向对比。</p><h3 id="相关资讯" tabindex="-1">相关资讯 <a class="header-anchor" href="#相关资讯" aria-label="Permalink to &quot;相关资讯&quot;">​</a></h3><p>行情页底部展示与该 ETF 相关的市场资讯和新闻，来源包括多家财经媒体。数据来自第三方数据源，仅供参考，不构成投资建议。</p><hr><h2 id="全景-tab" tabindex="-1">全景 Tab <a class="header-anchor" href="#全景-tab" aria-label="Permalink to &quot;全景 Tab&quot;">​</a></h2><p>全景标签提供 ETF 的基本面和分析数据，分为以下几个模块。</p><p>入口：个股详情页 - 全景</p><h3 id="概况" tabindex="-1">概况 <a class="header-anchor" href="#概况" aria-label="Permalink to &quot;概况&quot;">​</a></h3><ul><li><strong>基金简介</strong>：ETF 的投资目标、跟踪指数、基金规模、成立时间等基本信息</li><li><strong>营收构成 / 业绩构成</strong>：主要持仓行业或地区分布（按占比展示）</li><li><strong>关注度排名</strong>：在同类标的中的用户关注度排名（如「关注度 Top 26」）</li><li><strong>市值排名</strong>：在所属行业或板块中的市值排名（如「市值排名 17/92」）</li></ul><h3 id="股价趋势" tabindex="-1">股价趋势 <a class="header-anchor" href="#股价趋势" aria-label="Permalink to &quot;股价趋势&quot;">​</a></h3><p>展示 ETF 在不同时间维度下的涨跌幅表现：</p><table tabindex="0"><thead><tr><th>时间段</th><th>说明</th></tr></thead><tbody><tr><td>当日</td><td>今日涨跌幅</td></tr><tr><td>1 周</td><td>近 7 日涨跌幅</td></tr><tr><td>1 月</td><td>近 30 日涨跌幅</td></tr><tr><td>6 月</td><td>近 6 个月涨跌幅</td></tr><tr><td>今年</td><td>年初至今涨跌幅</td></tr><tr><td>1 年 / 3 年</td><td>近 1 年 / 3 年涨跌幅</td></tr><tr><td>全部</td><td>上市以来总涨跌幅</td></tr></tbody></table><p>同时显示<strong>社区看涨比例</strong>（如「看涨 84%」）和关注人数及表态条数。</p><h3 id="股票估值" tabindex="-1">股票估值 <a class="header-anchor" href="#股票估值" aria-label="Permalink to &quot;股票估值&quot;">​</a></h3><p>对 ETF 进行估值分析，提供三项核心估值指标：</p><ul><li><strong>市盈率（PE）</strong>：当前 PE 与历史区间、行业中位数的对比</li><li><strong>市净率（PB）</strong>：当前 PB 与历史区间、行业中位数的对比</li><li><strong>市销率（PS）</strong>：适合评估前期投入大、盈利周期慢的基金</li></ul><p>每项指标展示：当前值、合理区间、历史最大 / 最小值、平均值、中位值、行业中位数及同行业排名。</p><h3 id="财务评分" tabindex="-1">财务评分 <a class="header-anchor" href="#财务评分" aria-label="Permalink to &quot;财务评分&quot;">​</a></h3><p>根据最新财报综合评估基金财务状况，提供量化评分和描述（如「财务状况一般，环比有所恶化」），可与同行比较。</p><h3 id="成分股-持仓" tabindex="-1">成分股 / 持仓 <a class="header-anchor" href="#成分股-持仓" aria-label="Permalink to &quot;成分股 / 持仓&quot;">​</a></h3><blockquote><p>该模块展示 ETF 的持仓明细。</p></blockquote><ul><li><strong>成分股列表</strong>：ETF 跟踪指数的成分股名称、权重占比</li><li><strong>前十大持仓</strong>：持仓股票名称及持仓比例</li></ul><h3 id="分红" tabindex="-1">分红 <a class="header-anchor" href="#分红" aria-label="Permalink to &quot;分红&quot;">​</a></h3><p>历史分红记录，包含：</p><ul><li>除权除息日 / 登记日 / 派息日</li><li>每股（每份额）分红金额</li><li>分红频率（年度 / 季度 / 月度）</li></ul><h3 id="机构观点-分析师评级" tabindex="-1">机构观点 / 分析师评级 <a class="header-anchor" href="#机构观点-分析师评级" aria-label="Permalink to &quot;机构观点 / 分析师评级&quot;">​</a></h3><p>汇总机构分析师对该 ETF 或其跟踪标的的评级意见：</p><ul><li>评级分布：强力推荐 / 买入 / 持有 / 跑输大盘 / 无意见</li><li>目标价区间</li></ul><h3 id="股东信息" tabindex="-1">股东信息 <a class="header-anchor" href="#股东信息" aria-label="Permalink to &quot;股东信息&quot;">​</a></h3><ul><li><strong>主要股东</strong>：持股比例最高的机构或个人股东列表，含持股数量、持股比例、持股变动及披露时间</li><li><strong>基金持仓</strong>：哪些 ETF 或基金持有该标的（如 ARK Space Exploration ETF、Roundhill Space ETF 等），显示基金名称、持仓占比和更新时间</li></ul><h3 id="利益相关者-投资关系" tabindex="-1">利益相关者 / 投资关系 <a class="header-anchor" href="#利益相关者-投资关系" aria-label="Permalink to &quot;利益相关者 / 投资关系&quot;">​</a></h3><p>提供公司（或基金管理人）的投资者关系信息。</p><hr><blockquote><p>以上行情、资讯及其他数据来自第三方数据源，仅供参考，不构成投资建议。</p></blockquote>',60)])])}const c=a(l,[["render",o]]);export{p as __pageData,c as default};
